import{_ as t,o as s,c as a,ag as d}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"DICOMweb Proxy","description":"","frontmatter":{},"headers":[],"relativePath":"dicomweb-proxy.md","filePath":"dicomweb-proxy.md"}'),i={name:"dicomweb-proxy.md"};function o(n,e,r,c,l,h){return s(),a("div",null,[...e[0]||(e[0]=[d(`<h1 id="dicomweb-proxy" tabindex="-1">DICOMweb Proxy <a class="header-anchor" href="#dicomweb-proxy" aria-label="Permalink to &quot;DICOMweb Proxy&quot;">​</a></h1><p>Proxy Smart includes a built-in DICOMweb proxy at <code>/dicomweb/*</code> that forwards QIDO-RS and WADO-RS requests to an upstream PACS (e.g. Orthanc) while enforcing SMART on FHIR authentication.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The DICOMweb proxy enables SMART-authorized applications to query and retrieve medical imaging data without direct access to the PACS. Every request is authenticated via Bearer token, and all DICOM UIDs are validated before forwarding.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐     Bearer token     ┌──────────────┐    upstream auth    ┌──────────┐</span></span>
<span class="line"><span>│  SMART App  │ ──────────────────── │  Proxy Smart │ ─────────────────── │   PACS   │</span></span>
<span class="line"><span>│  (browser)  │   GET /dicomweb/...  │  /dicomweb/* │  GET /dicom-web/.. │ (Orthanc)│</span></span>
<span class="line"><span>└─────────────┘                      └──────────────┘                     └──────────┘</span></span></code></pre></div><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Environment Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>DICOMWEB_BASE_URL</code></td><td>—</td><td>DICOMweb root URL (e.g. <code>http://orthanc:8042/dicom-web</code>). Enables the proxy when set.</td></tr><tr><td><code>DICOMWEB_WADO_ROOT</code></td><td>same as base</td><td>Override the WADO-RS root URL</td></tr><tr><td><code>DICOMWEB_QIDO_ROOT</code></td><td>same as base</td><td>Override the QIDO-RS root URL</td></tr><tr><td><code>DICOMWEB_UPSTREAM_AUTH</code></td><td>—</td><td>Authorization header for the upstream PACS (e.g. <code>Basic dXNlcjpwYXNz</code>)</td></tr><tr><td><code>DICOMWEB_TIMEOUT_MS</code></td><td><code>30000</code></td><td>Upstream request timeout in milliseconds</td></tr></tbody></table><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><p>All endpoints require a valid SMART on FHIR Bearer token. DICOM UIDs are validated against the pattern <code>^[0-9.]+$</code>.</p><h3 id="qido-rs-query" tabindex="-1">QIDO-RS (Query) <a class="header-anchor" href="#qido-rs-query" aria-label="Permalink to &quot;QIDO-RS (Query)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/dicomweb/studies</code></td><td>Search studies by PatientName, PatientID, StudyDate, etc.</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series</code></td><td>Search series within a study</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances</code></td><td>Search instances within a series</td></tr></tbody></table><p>Query parameters are passed through to the upstream PACS. Common QIDO-RS query keys include <code>PatientName</code>, <code>PatientID</code>, <code>StudyDate</code>, <code>Modality</code>, and <code>limit</code>/<code>offset</code>.</p><h3 id="wado-rs-retrieve" tabindex="-1">WADO-RS (Retrieve) <a class="header-anchor" href="#wado-rs-retrieve" aria-label="Permalink to &quot;WADO-RS (Retrieve)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}</code></td><td>Retrieve all instances of a study (multipart DICOM)</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/metadata</code></td><td>Study metadata (DICOM JSON)</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/rendered</code></td><td>Rendered (JPEG/PNG) study image</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/thumbnail</code></td><td>Study thumbnail</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}</code></td><td>Retrieve a series (multipart DICOM)</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/metadata</code></td><td>Series metadata (DICOM JSON)</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/rendered</code></td><td>Rendered series image</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/thumbnail</code></td><td>Series thumbnail</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances/{sopUID}</code></td><td>Retrieve a single instance</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances/{sopUID}/metadata</code></td><td>Instance metadata</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances/{sopUID}/rendered</code></td><td>Rendered instance</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances/{sopUID}/thumbnail</code></td><td>Instance thumbnail</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances/{sopUID}/frames/{frame}</code></td><td>Retrieve specific frame(s)</td></tr><tr><td>GET</td><td><code>/dicomweb/studies/{studyUID}/series/{seriesUID}/instances/{sopUID}/bulkdata/*</code></td><td>Retrieve bulkdata by tag</td></tr></tbody></table><h3 id="response-handling" tabindex="-1">Response Handling <a class="header-anchor" href="#response-handling" aria-label="Permalink to &quot;Response Handling&quot;">​</a></h3><ul><li><strong>DICOM JSON</strong> responses (<code>metadata</code>, QIDO-RS) are returned as <code>application/dicom+json</code></li><li><strong>Binary</strong> responses (WADO-RS retrieve, frames, bulkdata) stream the upstream response directly, preserving <code>Content-Type</code> and <code>Transfer-Encoding</code> headers</li><li><strong>Rendered</strong> responses return <code>image/jpeg</code> or <code>image/png</code></li></ul><h2 id="development-setup" tabindex="-1">Development Setup <a class="header-anchor" href="#development-setup" aria-label="Permalink to &quot;Development Setup&quot;">​</a></h2><p>The development Docker Compose includes an Orthanc PACS:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># docker-compose.development.yml</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">orthanc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">jodogne/orthanc-plugins:1.12.8</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;8042:8042&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # DICOMweb + HTTP UI</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;4242:4242&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # DICOM DIMSE</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    ORTHANC__DICOM_WEB__ENABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;true&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    ORTHANC__DICOM_WEB__ROOT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/dicom-web/&quot;</span></span></code></pre></div><p>The backend connects via <code>DICOMWEB_BASE_URL=http://orthanc:8042/dicom-web</code>.</p><p>Upload test DICOM files via the Orthanc web UI at <code>http://localhost:8042</code> or using <code>storescu</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">storescu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4242</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> path/to/dicom/files/</span></span></code></pre></div><h2 id="authentication-flow" tabindex="-1">Authentication Flow <a class="header-anchor" href="#authentication-flow" aria-label="Permalink to &quot;Authentication Flow&quot;">​</a></h2><ol><li>Client sends <code>GET /dicomweb/studies</code> with <code>Authorization: Bearer &lt;smart_token&gt;</code></li><li>Proxy validates the SMART token (JWT signature, expiry, scopes)</li><li>Proxy builds the upstream PACS URL and forwards the request</li><li>If <code>DICOMWEB_UPSTREAM_AUTH</code> is configured, it&#39;s added as the <code>Authorization</code> header to the upstream request</li><li>The PACS response is streamed back to the client</li></ol><h2 id="production-deployment" tabindex="-1">Production Deployment <a class="header-anchor" href="#production-deployment" aria-label="Permalink to &quot;Production Deployment&quot;">​</a></h2><p>In production, point <code>DICOMWEB_BASE_URL</code> to your PACS DICOMweb endpoint. The proxy supports any DICOMweb-compliant server (Orthanc, DCM4CHEE, Google Cloud Healthcare API, Azure DICOM, etc.).</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DICOMWEB_BASE_URL=https://pacs.hospital.org/dicom-web</span></span>
<span class="line"><span>DICOMWEB_UPSTREAM_AUTH=Bearer &lt;service_token&gt;</span></span>
<span class="line"><span>DICOMWEB_TIMEOUT_MS=60000</span></span></code></pre></div>`,27)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
